{"content":"1: /**
2:  * @fileoverview The MarkdownSourceCode class.
3:  * @author Nicholas C. Zakas
4:  */
5: 
6: //-----------------------------------------------------------------------------
7: // Imports
8: //-----------------------------------------------------------------------------
9: 
10: import {
11: 	VisitNodeStep,
12: 	TextSourceCodeBase,
13: 	ConfigCommentParser,
14: 	Directive,
15: } from "@eslint/plugin-kit";
16: import { findOffsets } from "../util.js";
17: 
18: //-----------------------------------------------------------------------------
19: // Types
20: //-----------------------------------------------------------------------------
21: 
22: /** @typedef {import("mdast").Root} RootNode */
23: /** @typedef {import("mdast").Node} MarkdownNode */
24: /** @typedef {import("mdast").Html} HTMLNode */
