79: 	if (!configCommentStart.test(node.value)) {
80: 		return [];
81: 	}
82: 	const comments = [];
83: 
84: 	let match;
85: 
86: 	while ((match = htmlComment.exec(node.value))) {
87: 		if (configCommentStart.test(match[0])) {
88: 			const comment = match[0];
