229: 				comment.position.start.line !== comment.position.end.line
230: 			) {
231: 				const message = `${label} comment should not span multiple lines.`;
232: 
233: 				problems.push({
234: 					ruleId: null,
235: 					message,
236: 					loc: comment.position,
237: 				});
238: 				return;
239: 			}
240: 
241: 			// Step 3: Extract the directive value and create the Directive object
242: 			switch (label) {
243: 				case "eslint-disable":
244: 				case "eslint-enable":
245: 				case "eslint-disable-next-line":
246: 				case "eslint-disable-line": {
247: 					const directiveType = label.slice("eslint-".length);
248: 
249: 					directives.push(
250: 						new Directive({
251: 							type: /** @type {DirectiveType} */ (directiveType),
252: 							node: comment,
253: 							value,
254: 							justification: justificationPart,
255: 						}),
256: 					);
257: 				}
258: 
259: 				// no default
260: 			}
261: 		});
262: 
263: 		return { problems, directives };
264: 	}
