274: 		}
275: 
276: 		/** @type {Array<VisitNodeStep>} */
277: 		const steps = (this.#steps = []);
278: 
279: 		const visit = (node, parent) => {
280: 			// first set the parent
281: 			this.#parents.set(node, parent);
282: 
283: 			// then add the step
284: 			steps.push(
285: 				new VisitNodeStep({
286: 					target: node,
287: 					phase: 1,
288: 					args: [node, parent],
289: 				}),
290: 			);
291: 
292: 			// save HTML nodes
293: 			if (node.type === "html") {
294: 				this.#htmlNodes.push(node);
295: 			}
296: 
297: 			// then visit the children
298: 			if (node.children) {
299: 				node.children.forEach(child => {
300: 					visit(child, node);
301: 				});
302: 			}
303: 
304: 			// then add the exit step
305: 			steps.push(
306: 				new VisitNodeStep({
307: 					target: node,
308: 					phase: 2,
309: 					args: [node, parent],
310: 				}),
311: 			);
312: 		};
313: 
314: 		visit(this.ast);
315: 
316: 		return steps.values();
317: 	}
